  return (
    <div style={{ padding: '40px', width: '100%', maxWidth: '800px' }}>
      <h2 style={{ 
        fontSize: '0.8rem', 
        fontWeight: 900, 
        color: 'var(--gold)', 
        letterSpacing: '0.2em',
        marginBottom: '24px',
        borderLeft: '4px solid var(--gold)',
        paddingLeft: '12px'
      }}>
        NEURAL MAP: VOCABULARY & GRAMMAR
      </h2>

      <div style={{ 
        display: 'grid', 
        gridTemplateColumns: widgetDensity === 'Compact' ? 'repeat(4, 1fr)' : 'repeat(2, 1fr)', 
        gap: '16px' 
      }}>
        {sortedVocab.map(v => (
          <LiveTile 
            key={v.id} 
