                          background: node.status === 'mastered' ? 'rgba(34, 197, 94, 0.1)' : 'rgba(255,255,255,0.03)',
                          border: `1px solid ${node.status === 'active' ? 'var(--gold)' : 'var(--border)'}`,
                          borderRadius: '6px',
                          display: 'flex',
                          justifyContent: 'space-between',
