import type { Unsubscribe } from 'firebase/firestore';
import type { 
  MasteryStatus, VocabWord, StatusSummary, SavedPhrase, 
  UserProfile, LoreEntry, ReviewVibe, LoreCategory, 
  CurriculumLevel, NodeStatus 
