import MasteryGrid from './MasteryGrid';
import PhraseGrid from './PhraseGrid';
import type { MasteryStatus } from '../types/mastery';
import type { AppPanel } from '../App';


export default function Dashboard({ onTogglePanel, activePanels, onAskLina, isSandboxMode, setIsSandboxMode }: {
  onTogglePanel: (p: AppPanel) => void;
  activePanels: AppPanel[];
  onAskLina: (p: string) => void;
  isSandboxMode: boolean;
  setIsSandboxMode: (val: boolean) => void;
}) {
  const { studentName, currentStreak, vocabulary, savedPhrases, reviewVibe, setReviewVibe } = useMasteryStore();

  const [activeFilter, setActiveFilter] = useState<MasteryStatus | null>(null);
  const [viewMode, setViewMode] = useState<'grid' | 'phrasebook'>('grid');
  const [posFilter, setPosFilter] = useState('All');
  const [sortMode, setSortMode] = useState<string>('alphabetical');
  const [sortDirection, setSortDirection] = useState<'asc' | 'desc'>('asc');
  const [focusPhraseId, setFocusPhraseId] = useState<string | null>(null);

  const handleDailyReview = () => {
    let targetWords: string[] = [];
    if (reviewVibe === 'chill') {
      targetWords = vocabulary
        .filter(w => w.status === 'confident' || w.status === 'mastered')
        .sort((a, b) => b.confidenceScore - a.confidenceScore)
        .slice(0, 8)
        .map(w => w.word);
    } else {
      targetWords = vocabulary
        .filter(w => w.status === 'introduced' || w.status === 'not_started')
        .sort((a, b) => (a.frequencyRank ?? 999) - (b.frequencyRank ?? 999))
        .slice(0, 6)
        .map(w => w.word);
    }

    if (targetWords.length === 0) {
      onAskLina(`toki jan Lina! I'm in ${reviewVibe} mode but I have no words that fit that criteria. What should we work on instead?`);
      return;
    }
    onAskLina(`toki jan Lina! Let's do a daily review in **${reviewVibe.toUpperCase()}** mode. Focus on these words: ${targetWords.join(', ')}. Please follow the standard 3-phase lesson structure.`);
  };

  const handleSaved = (phraseId: string) => {
    setFocusPhraseId(phraseId);
    setViewMode('phrasebook');
  };

  const getActiveStyle = (p: AppPanel) => activePanels.includes(p) ? { borderColor: 'var(--gold)', color: 'var(--gold)' } : {};

  return (
    <div className="dashboard">
      <header className="dashboard__header">
        <div className="dashboard__header-left">
          <h1 className="dashboard__title">TOKI PONA</h1>
          <button 
            onClick={() => onTogglePanel('profile')} 
            className="dashboard__profile-trigger"
            style={getActiveStyle('profile')}
          >
            👤 {studentName?.toUpperCase() || 'STUDENT'}
          </button>
        </div>
        <div className="dashboard__header-right">
          {currentStreak > 0 && (
            <div 
              className="dashboard__streak" 
              onClick={() => onTogglePanel('achievements')}
              style={getActiveStyle('achievements')}
            >
              🔥 {currentStreak}
            </div>
          )}
          <button onClick={() => onTogglePanel('instructions')} className="dashboard__icon-btn" style={getActiveStyle('instructions')}>?</button>
          <button onClick={() => onTogglePanel('chat')} className="dashboard__icon-btn" style={getActiveStyle('chat')}>💬</button>
          <button onClick={() => onTogglePanel('settings')} className="dashboard__icon-btn" style={getActiveStyle('settings')}>⚙️</button>
        </div>
      </header>

      <main className="dashboard__main">
        <ProgressSummary activeFilter={activeFilter} onFilterClick={setActiveFilter} />

        <div style={{ display: 'flex', gap: '8px', marginBottom: '12px' }}>
          <button onClick={handleDailyReview} className="btn-review" style={{ flex: 1, marginBottom: 0 }}>
            ⚡ START DAILY REVIEW
          </button>
          <div style={{ display: 'flex', background: 'var(--surface)', borderRadius: '4px', padding: '4px', border: '1px solid var(--border)' }}>
            <button 
              onClick={() => setReviewVibe('chill')}
              style={{ border: 'none', background: reviewVibe === 'chill' ? 'var(--gold)' : 'transparent', color: reviewVibe === 'chill' ? 'black' : '#666', borderRadius: '2px', padding: '0 12px', fontSize: '0.6rem', fontWeight: 900, cursor: 'pointer' }}
            >
              CHILL
            </button>
            <button 
              onClick={() => setReviewVibe('deep')}
              style={{ border: 'none', background: reviewVibe === 'deep' ? 'var(--gold)' : 'transparent', color: reviewVibe === 'deep' ? 'black' : '#666', borderRadius: '2px', padding: '0 12px', fontSize: '0.6rem', fontWeight: 900, cursor: 'pointer' }}
            >
              DEEP
            </button>
          </div>
        </div>

        <div className="dashboard__view-toggle">
          <button onClick={() => setViewMode('grid')} className={`btn-toggle ${viewMode === 'grid' ? 'active' : ''}`}>VOCAB GRID</button>
          <button onClick={() => setViewMode('phrasebook')} className={`btn-toggle ${viewMode === 'phrasebook' ? 'active' : ''}`}>PHRASEBOOK</button>
        </div>

        {viewMode === 'grid' ? (
          <>
            <div className="grid-toolbar">
              <select value={posFilter} onChange={(e) => setPosFilter(e.target.value)} className="sort-select">
                <option value="All">All Parts of Speech</option>
                <option value="noun">Noun</option>
                <option value="verb">Verb</option>
                <option value="adjective">Adjective</option>
                <option value="adverb">Adverb</option>
                <option value="number">Number</option>
                <option value="phrase">Phrase</option>
              </select>
            </div>
            <MasteryGrid
              onAskLina={onAskLina}
              onSaved={handleSaved}
              isSandboxMode={isSandboxMode}
              activeFilter={activeFilter}
              sortMode={sortMode}
              sortDirection={sortDirection}
              posFilter={posFilter}
              setSortMode={setSortMode}
              setSortDirection={setSortDirection}
              setPosFilter={setPosFilter}
            />
          </>
        ) : (
          <div style={{ padding: '20px 0' }}>
            <PhraseGrid
              onAskLina={onAskLina}
              activeFilter={activeFilter}
              selectedWords={[]}
              focusPhraseId={focusPhraseId}
              clearFocusPhrase={() => setFocusPhraseId(null)}
            />
            <h3 className="section-title" style={{ marginTop: '30px', marginBottom: '15px' }}>SAVED PHRASES</h3>
            {savedPhrases.length === 0 ? <p style={{ color: '#888' }}>No phrases saved yet.</p> : savedPhrases.map((p, i) => (
              <div key={i} className="glass-panel" style={{ borderLeft: '4px solid var(--green)', marginBottom: '10px' }}>
                {typeof p === 'string' ? p : p.tp}
              </div>
            ))}
          </div>
        )}
      </main>
    </div>
  );
}

/* src/components/ProgressSummary.tsx */
import { useMasteryStore } from '../store/masteryStore';
import type { MasteryStatus } from '../types/mastery';

interface Props {
  activeFilter: MasteryStatus | null;
  onFilterClick: (status: MasteryStatus | null) => void;
}

export default function ProgressSummary({ activeFilter, onFilterClick }: Props) {
  const _vocab = useMasteryStore((s) => s.vocabulary);
  const getStatusSummary = useMasteryStore((s) => s.getStatusSummary);
  const summary = getStatusSummary();

  const statusItems: { status: MasteryStatus; label: string; emoji: string; color: string; glow: string }[] = [
    { status: 'not_started', label: 'NOT STARTED', emoji: '⬜', color: '#9ca3af', glow: 'rgba(156,163,175,0.5)' },
    { status: 'introduced',  label: 'INTRODUCED',  emoji: '🔵', color: '#3b82f6', glow: 'rgba(59,130,246,0.6)'  },
    { status: 'practicing',  label: 'PRACTICING',  emoji: '🟡', color: '#f59e0b', glow: 'rgba(245,158,11,0.6)'  },
    { status: 'confident',   label: 'CONFIDENT',   emoji: '🟢', color: '#16a34a', glow: 'rgba(22,163,74,0.6)'   },
    { status: 'mastered',    label: 'MASTERED',    emoji: '✅', color: '#22c55e', glow: 'rgba(34,197,94,0.65)'  },
  ];

  return (
    <div style={{ background: '#111', borderRadius: '16px', padding: '14px', border: '1px solid #222', marginBottom: '14px' }}>
      <div style={{ display: 'grid', gridTemplateColumns: 'repeat(5, 1fr)', gap: '6px' }}>
        {statusItems.map((item) => {
          const isActive = activeFilter === item.status;
          const isDimmed = activeFilter !== null && !isActive;
          const shouldGlow = activeFilter === null || isActive;

          return (
            <button
              key={item.status}
              onClick={() => onFilterClick(isActive ? null : item.status)}
              style={{
                background: isActive ? `${item.color}22` : '#0d0d0d',
                border: isActive ? `2px solid ${item.color}` : `1px solid ${item.color}44`,
                padding: '10px 4px 8px',
                borderRadius: '12px',
                cursor: 'pointer',
                transition: 'all 0.25s ease',
                opacity: isDimmed ? 0.3 : 1,
                boxShadow: shouldGlow
                  ? `0 0 14px ${item.glow}, 0 0 4px ${item.glow}`
                  : 'none',
                transform: isActive ? 'scale(1.06)' : 'scale(1)',
                display: 'flex',
                flexDirection: 'column',
                alignItems: 'center',
                gap: '4px',
              }}
            >
              <span style={{ fontSize: '1.1rem', lineHeight: 1 }}>{item.emoji}</span>
              <span style={{ fontSize: '1rem', fontWeight: 'bold', color: item.color, lineHeight: 1 }}>
                {summary[item.status]}
              </span>
              <span style={{
                fontSize: '0.48rem',
                color: isActive ? item.color : `${item.color}99`,
                fontWeight: '700',
                letterSpacing: '0.04em',
              }}>
                {item.label}
              </span>
            </button>
          );
        })}
      </div>
    </div>
  );
}

/* src/components/MasteryGrid.tsx */
import { useState, useRef, useEffect } from 'react';
import { useMasteryStore } from '../store/masteryStore';
import VocabCard from './VocabCard';
import WordDetailDrawer from './WordDetailDrawer';
import { fetchSentenceSuggestions, fetchQuickTranslation, resolveApiKey, buildOfflineTranslation, stringifyUserContext } from '../services/linaService';
import type { MasteryStatus, VocabWord } from '../types/mastery';

interface Props {
  onAskLina: (p: string) => void;
  onSaved?: (phraseId: string) => void;
  isSandboxMode: boolean;
  activeFilter: MasteryStatus | null;
  sortMode: string;
  sortDirection: 'asc' | 'desc';
  posFilter: string;
  setSortMode: (mode: any) => void;
  setSortDirection: (dir: any) => void;
  setPosFilter: (pos: string) => void;
}

const STATUS_RANK: Record<MasteryStatus, number> = {
  not_started: 0, introduced: 1, practicing: 2, confident: 3, mastered: 4
};

export default function MasteryGrid({
  onAskLina, onSaved, isSandboxMode, activeFilter, sortMode, sortDirection, posFilter,
  setSortMode, setSortDirection, setPosFilter
}: Props) {
  const { vocabulary, savePhrase, profile, lore } = useMasteryStore();
  const [selectedWords, setSelectedWords] = useState<string[]>([]);
  const [drawerId, setDrawerId] = useState<string | null>(null);
  const [magneticSuggestions, setMagneticSuggestions] = useState<string[]>([]);
  const [translation, setTranslation] = useState<string | null>(null);
  const [isAutoTranslating, setIsAutoTranslating] = useState(false);
  const [savedConfirm, setSavedConfirm] = useState(false);

  const confirmTimer  = useRef<ReturnType<typeof setTimeout> | null>(null);

  useEffect(() => {
    setTranslation(null);
    setIsAutoTranslating(false);
    if (confirmTimer.current) { clearTimeout(confirmTimer.current); confirmTimer.current = null; }
    setSavedConfirm(false);

    if (selectedWords.length === 0) { setMagneticSuggestions([]); return; }

    if (isSandboxMode) {
      setTranslation(buildOfflineTranslation(selectedWords, vocabulary));
      setMagneticSuggestions([]);
      return;
    }

    const apiKey = resolveApiKey();
    if (!apiKey) {
      setTranslation(buildOfflineTranslation(selectedWords, vocabulary));
      setMagneticSuggestions([]);
      return;
    }

    setIsAutoTranslating(true);
    let active = true;
    const timer = setTimeout(async () => {
      const uniqueWords = [...new Set(selectedWords)];
      const userContext = stringifyUserContext(profile, lore);
      const [transResult, suggResults] = await Promise.all([
        fetchQuickTranslation(apiKey, selectedWords.join(' ')),
        selectedWords.length >= 2
          ? fetchSentenceSuggestions(apiKey, uniqueWords, userContext)
          : Promise.resolve([]),
      ]);
      if (active) {
        setTranslation(transResult ?? buildOfflineTranslation(selectedWords, vocabulary));
        setMagneticSuggestions(suggResults);
        setIsAutoTranslating(false);
      }
    }, 900);

    return () => { active = false; clearTimeout(timer); setIsAutoTranslating(false); };
  }, [selectedWords, isSandboxMode, profile, lore, vocabulary]);

  const handleCardClick = (word: VocabWord) => {
    if (selectedWords.length === 0) {
      setDrawerId(word.id);
    } else {
      setSelectedWords(prev => [...prev, word.word]);
    }
  };

  const handleCardLongPress = (word: VocabWord) => {
    if (selectedWords.length > 0) {
      setSelectedWords(prev => [...prev, word.word]);
    } else {
      setDrawerId(word.id);
    }
  };

  const handleSave = () => {
    const sentence = selectedWords.join(' ');
    savePhrase({ id: sentence, tp: sentence, en: translation ?? '', notes: '' });
    if (confirmTimer.current) clearTimeout(confirmTimer.current);
    setSavedConfirm(true);
    confirmTimer.current = setTimeout(() => {
      setSavedConfirm(false);
      confirmTimer.current = null;
      setSelectedWords([]);
      onSaved?.(sentence);
    }, 800);
  };

  const displayed = vocabulary
    .filter(w => posFilter === 'All' || w.partOfSpeech.toLowerCase().includes(posFilter.toLowerCase()))
    .sort((a, b) => {
      if (sortMode === 'status') {
        const diff = STATUS_RANK[a.status] - STATUS_RANK[b.status];
        return sortDirection === 'asc' ? diff : -diff;
      }
      if (sortMode === 'length') {
        const diff = a.word.length - b.word.length;
        return sortDirection === 'asc' ? diff : -diff;
      }
      if (sortMode === 'partOfSpeech') {
        const diff = a.partOfSpeech.localeCompare(b.partOfSpeech);
        return sortDirection === 'asc' ? diff : -diff;
      }
      if (sortMode === 'useCount') {
        const diff = (a.frequencyRank ?? 999) - (b.frequencyRank ?? 999);
        return sortDirection === 'asc' ? diff : -diff;
      }
      const valA = a.word.toLowerCase();
      const valB = b.word.toLowerCase();
      return sortDirection === 'asc' ? valA.localeCompare(valB) : valB.localeCompare(valA);
    });

  return (
    <div
      className="mastery-grid-container"
      style={{ paddingBottom: selectedWords.length > 0 ? '240px' : undefined }}
      onClick={(e) => { if (e.target === e.currentTarget && selectedWords.length > 0) setSelectedWords([]); }}
    >
      <div className="grid-toolbar">
        <select value={sortMode} onChange={(e) => setSortMode(e.target.value)} className="sort-select">
          <option value="alphabetical">A → Z</option>
          <option value="status">Mastery Level</option>
          <option value="length">Word Length</option>
          <option value="partOfSpeech">Part of Speech</option>
          <option value="useCount">Most Used</option>
        </select>
        <button
          onClick={(e) => { e.stopPropagation(); setSortDirection(sortDirection === 'asc' ? 'desc' : 'asc'); }}
          className="btn-toggle"
          style={{ flex: 'none', width: '42px' }}
        >
          {sortDirection === 'asc' ? '↑' : '↓'}
        </button>
      </div>

      <div className="mastery-grid__cards">
        {displayed.map((word) => {
          const positions: number[] = [];
          selectedWords.forEach((w, i) => { if (w === word.word) positions.push(i + 1); });
          const isSelected = positions.length > 0;
          const isFilterDimmed = activeFilter && word.status !== activeFilter;

          return (
            <div
              key={word.id}
              className="grid-item-wrapper"
              style={{
                position: 'relative',
                opacity: (selectedWords.length > 0 && !isSelected) || isFilterDimmed ? 0.3 : 1,
                cursor: 'pointer',
                transition: 'opacity 0.25s ease',
              }}
              onClick={(e) => e.stopPropagation()}
            >
              <VocabCard 
                word={word} 
                onClick={handleCardClick}
                onLongPress={handleCardLongPress}
              />

              {positions.length > 0 && (
                <div style={{
                  position: 'absolute',
                  top: 3,
                  right: 3,
                  display: 'flex',
                  flexWrap: 'wrap',
                  gap: '2px',
                  justifyContent: 'flex-end',
                  maxWidth: '64px',
                  pointerEvents: 'none',
                }}>
                  {positions.map(pos => (
                    <span
                      key={pos}
                      style={{
                        background: '#3b82f6',
                        color: 'white',
                        borderRadius: '50%',
                        width: '16px',
                        height: '16px',
                        fontSize: '0.58rem',
                        fontWeight: 800,
                        display: 'flex',
                        alignItems: 'center',
                        justifyContent: 'center',
                        lineHeight: 1,
                        boxShadow: '0 1px 3px rgba(0,0,0,0.6)',
                      }}
                    >
                      {pos}
                    </span>
                  ))}
                </div>
              )}
            </div>
          );
        })}
      </div>

      {selectedWords.length > 0 && (
        <div className="builder-panel" onClick={(e) => e.stopPropagation()}>
          <div className="builder-content">
            <div style={{
              minHeight: '20px',
              color: isAutoTranslating ? '#444' : '#64748b',
              fontSize: '0.78rem',
              fontStyle: 'italic',
              marginBottom: '12px',
              letterSpacing: '0.01em',
            }}>
              {isAutoTranslating ? '· · ·' : (translation ?? '')}
            </div>

            <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-end', marginBottom: '10px', gap: '8px' }}>
              <div style={{ display: 'flex', flexWrap: 'wrap', gap: '8px', flex: 1 }}>
                {selectedWords.map((w, idx) => {
                  const vocab = vocabulary.find(v => v.word === w);
                  const meaning = vocab?.meanings?.split(',')[0].trim() || '';
                  return (
                    <div key={idx} style={{ display: 'flex', flexDirection: 'column', alignItems: 'center' }}>
                      <div style={{ fontSize: '0.6rem', color: '#888', textTransform: 'uppercase', fontWeight: 700, marginBottom: '2px' }}>{meaning}</div>
                      <div style={{ color: 'white', fontSize: '1.2rem', fontWeight: 'bold' }}>{w}</div>
                    </div>
                  );
                })}
              </div>
              <button
                onClick={() => setSelectedWords(prev => prev.slice(0, -1))}
                className="btn-toggle"
                style={{ flex: 'none', width: '34px', height: '34px', padding: 0, fontSize: '0.9rem', marginBottom: '4px' }}
                title="Remove last word"
              >⌫</button>
            </div>

            {magneticSuggestions.length > 0 && (
              <div style={{ display: 'flex', gap: '8px', flexWrap: 'wrap', marginBottom: '12px' }}>
                {magneticSuggestions.map((s, i) => (
                  <button
                    key={i}
                    className="suggestion-pill"
                    onClick={() => { onAskLina(`Let's practice this: "${s}"`); setSelectedWords([]); }}
                  >
                    {s}
                  </button>
                ))}
              </div>
            )}

            <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr 1fr', gap: '8px' }}>
              <button
                onClick={() => { onAskLina(`toki jan Lina! Let's work on: "${selectedWords.join(' ')}" — is this correct Toki Pona?`); setSelectedWords([]); }}
                className="btn-review"
                style={{ margin: 0, fontSize: '0.72rem', padding: '10px 4px' }}
              >
                ASK JAN LINA
              </button>
              <button
                onClick={() => setSelectedWords([])}
                className="btn-review"
                style={{ margin: 0, fontSize: '0.72rem', padding: '10px 4px', background: '#374151' }}
              >
                CLEAR
              </button>
              <button
                onClick={handleSave}
                className="btn-review"
                style={{ margin: 0, fontSize: '0.72rem', padding: '10px 4px', background: savedConfirm ? '#10b981' : undefined }}
              >
                {savedConfirm ? 'SAVED ✓' : 'SAVE'}
              </button>
            </div>
          </div>
        </div>
      )}

      <WordDetailDrawer
        isOpen={!!drawerId}
        word={drawerId ? vocabulary.find(v => v.id === drawerId) ?? null : null}
        onClose={() => setDrawerId(null)}
        onAskLina={onAskLina}
        isSandboxMode={isSandboxMode}
      />
    </div>
  );
}

/* src/App.css */

/* Global Theme Styles */
:root {
  --neon-glow: 0 0 10px rgba(0, 243, 255, 0.4);
  --neon-glow-strong: 0 0 20px rgba(0, 243, 255, 0.6);
}

/* Enable text selection for chat messages and full-screen views */
.chat-drawer, 
.chat-drawer *, 
.full-screen-view,
.full-screen-view *,
.modal-content,
.modal-content * {
  user-select: text !important;
  -webkit-user-select: text !important;
}

/* Glassmorphism utility */
.glass-panel {
  background: var(--surface);
  backdrop-filter: var(--glass);
  border: 1px solid var(--border);
  box-shadow: 0 8px 32px 0 rgba(0, 0, 0, 0.37);
}

/* Inputs */
.settings-input {
  width: 100%;
  padding: 12px 16px;
  background: rgba(255, 255, 255, 0.03);
  border: 1px solid var(--border);
  color: white;
  border-radius: 12px;
  margin-bottom: 12px;
  font-size: 0.95rem;
  font-family: var(--font);
  outline: none;
  transition: all 0.2s;
}

.settings-input:focus {
  border-color: var(--cyan);
  background: rgba(0, 243, 255, 0.02);
  box-shadow: 0 0 10px rgba(0, 243, 255, 0.1);
}

/* Settings Row */
.settings-row {
  display: flex;
  justify-content: space-between;
  align-items: center;
  color: white;
  cursor: pointer;
  padding: 8px 0;
}

/* Checkbox */
.settings-checkbox {
  width: 20px;
  height: 20px;
  cursor: pointer;
  accent-color: var(--cyan);
}

/* Buttons */
.btn-settings {
  display: block;
  width: 100%;
  padding: 14px;
  background: #0a0a0a;
  color: var(--gold);
  border: 1px solid rgba(255, 191, 0, 0.2);
  border-radius: 2px;
  font-weight: 700;
  font-size: 0.85rem;
  letter-spacing: 0.05em;
  cursor: pointer;
  text-transform: uppercase;
  transition: all 0.2s;
}

.btn-settings:hover {
  border-color: var(--gold);
  box-shadow: 0 0 15px rgba(255, 191, 0, 0.1);
  background: rgba(255, 191, 0, 0.05);
}

.btn-close-glowing {
  background: none;
  border: none;
  color: var(--gold);
  font-size: 1.5rem;
  font-weight: 300;
  cursor: pointer;
  display: flex;
  align-items: center;
  justify-content: center;
  width: 40px;
  height: 40px;
  transition: all 0.2s;
  text-shadow: 0 0 10px var(--gold-glow);
}

.btn-close-glowing:hover {
  transform: scale(1.1);
  text-shadow: 0 0 20px var(--gold-glow);
}

/* Danger Zone */
.danger-zone {
  border: 1px solid rgba(239, 68, 68, 0.2);
  padding: 20px;
  border-radius: 20px;
  margin-top: 32px;
  background: rgba(239, 68, 68, 0.02);
}

.btn-danger {
  display: block;
  width: 100%;
  padding: 14px;
  background: transparent;
  color: #ef4444;
  border: 1px solid rgba(239, 68, 68, 0.3);
  border-radius: 12px;
  font-weight: 700;
  font-size: 0.85rem;
  letter-spacing: 0.05em;
  cursor: pointer;
  transition: all 0.2s;
}

.btn-danger:hover {
  background: rgba(239, 68, 68, 0.1);
  border-color: #ef4444;
}

/* Animations */
@keyframes pulse {
  0% { opacity: 0.6; }
  50% { opacity: 0.3; }
  100% { opacity: 0.6; }
}

.pulse {
  animation: pulse 1.5s infinite ease-in-out;
}

/* ─── Reset & Base ──────────────────────────────────────────────────────── */
*, *::before, *::after {
  box-sizing: border-box;
  margin: 0;
  padding: 0;
}

:root {
  --font: 'Inter', system-ui, -apple-system, sans-serif;
  --bg: #050505;
  --surface: rgba(10, 10, 10, 0.85);
  --surface-opaque: #0a0a0a;
  --surface-2: rgba(20, 20, 20, 0.9);
  --border: rgba(192, 192, 192, 0.2);
  --text: #e0e0e0;
  --text-muted: #888;
  --gold: #ffbf00;
  --gold-glow: rgba(255, 191, 0, 0.4);
  --silver: #c0c0c0;
  --cyan: #00f3ff;
  --blue: #3b82f6;
  --amber: #f59e0b;
  --green: #10b981;
  --pink: #ec4899;
  --header-height: 64px;
  --glass: blur(25px);
  --panel-width: 400px;
}

html, body {
  background: var(--bg);
  color: var(--text);
  font-family: var(--font);
  height: 100%;
  overflow: hidden;
}

#root {
  height: 100%;
}

button {
  font-family: var(--font);
  cursor: pointer;
  transition: all 0.2s cubic-bezier(0.4, 0, 0.2, 1);
}

select {
  font-family: var(--font);
  appearance: none;
  cursor: pointer;
}

/* ─── Layout ───────────────────────────────────────────────────────────── */
.app-container {
  display: flex;
  height: 100dvh;
  background: var(--bg);
  overflow-x: auto;
}

.dashboard {
  flex: 1;
  display: flex;
  flex-direction: column;
  height: 100%;
  min-width: 600px;
  background: var(--bg);
  background-image: 
    radial-gradient(circle at 0% 0%, rgba(255, 191, 0, 0.02) 0%, transparent 40%),
    radial-gradient(circle at 100% 100%, rgba(255, 191, 0, 0.02) 0%, transparent 40%);
}

.dashboard__header {
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding: 0 16px;
  height: var(--header-height);
  background: rgba(5, 5, 5, 0.95);
  backdrop-filter: var(--glass);
  border-bottom: 1px solid var(--border);
  flex-shrink: 0;
  gap: 12px;
}

.dashboard__header-left {
  display: flex;
  align-items: center;
  gap: 12px;
  min-width: 0;
}

.dashboard__header-right {
  display: flex;
  align-items: center;
  gap: 8px;
  flex-shrink: 0;
}

.dashboard__title {
  font-size: 1.1rem;
  font-weight: 900;
  letter-spacing: 0.2em;
  color: var(--text);
  white-space: nowrap;
  text-transform: uppercase;
  background: linear-gradient(to right, #fff, var(--gold));
  -webkit-background-clip: text;
  -webkit-text-fill-color: transparent;
}

.dashboard__profile-trigger {
  background: var(--surface);
  border: 1px solid var(--border);
  color: var(--text);
  padding: 8px 14px;
  border-radius: 2px;
  font-size: 0.75rem;
  font-weight: 700;
  letter-spacing: 0.05em;
  cursor: pointer;
  display: flex;
  align-items: center;
  gap: 8px;
  white-space: nowrap;
  overflow: hidden;
  text-overflow: ellipsis;
  max-width: 180px;
  text-transform: uppercase;
}

.dashboard__profile-trigger:hover {
  border-color: var(--gold);
  box-shadow: 0 0 15px var(--gold-glow);
}

.dashboard__streak {
  background: var(--surface);
  border: 1px solid var(--border);
  color: var(--gold);
  padding: 8px 14px;
  border-radius: 2px;
  font-size: 0.85rem;
  font-weight: 700;
  white-space: nowrap;
  cursor: pointer;
  transition: all 0.2s;
}

.dashboard__streak:hover {
  border-color: var(--gold);
  box-shadow: 0 0 10px var(--gold-glow);
}

.dashboard__icon-btn {
  background: var(--surface);
  border: 1px solid var(--border);
  color: var(--text);
  width: 38px;
  height: 38px;
  border-radius: 2px;
  font-size: 1.1rem;
  display: flex;
  align-items: center;
  justify-content: center;
  cursor: pointer;
  flex-shrink: 0;
}

.dashboard__icon-btn:hover {
  border-color: var(--gold);
  color: var(--gold);
}

.dashboard__main {
  flex: 1;
  overflow-y: auto;
  padding: 20px;
  -webkit-overflow-scrolling: touch;
}

.dashboard__view-toggle {
  display: flex;
  gap: 2px;
  margin-bottom: 20px;
  background: rgba(255,255,255,0.03);
  padding: 2px;
  border-radius: 2px;
}

/* ─── Side Panels Stack ────────────────────────────────────────────────── */
.side-panels-container {
  display: flex;
  flex-direction: row;
  height: 100%;
  flex-shrink: 0;
}

.side-panel {
  width: var(--panel-width);
  height: 100%;
  border-left: 1px solid var(--border);
  background: var(--surface-opaque);
  display: flex;
  flex-direction: column;
  position: relative;
  z-index: 10;
  overflow: hidden;
}

.side-panels-container.left-dock .side-panel {
  border-left: none;
  border-right: 1px solid var(--border);
}

.resize-handle {
  position: absolute;
  top: 0;
  bottom: 0;
  width: 6px;
  cursor: col-resize;
  z-index: 20;
  transition: background 0.2s;
}

.resize-handle:hover, .resize-handle.active {
  background: var(--gold-glow);
}

.resize-handle--left { left: 0; }
.resize-handle--right { right: 0; }

/* Mobile specific for panels */
@media (max-width: 1023px) {
  .side-panel {
    position: fixed;
    inset: 0;
    width: 100%;
    z-index: 3000;
  }

  .chat-drawer {
    height: 92vh !important;
    top: auto !important;
    bottom: 0 !important;
  }
}

/* ─── Buttons ───────────────────────────────────────────────────────────── */
.btn-review {
  display: block;
  width: 100%;
  margin-bottom: 16px;
  padding: 14px 24px;
  background: var(--gold);
  color: #000;
  border: none;
  border-radius: 2px;
  font-weight: 900;
  font-size: 0.85rem;
  letter-spacing: 0.15em;
  cursor: pointer;
  text-transform: uppercase;
  box-shadow: 0 4px 20px rgba(255, 191, 0, 0.2);
}

.btn-review:hover { 
  transform: translateY(-1px);
  box-shadow: 0 6px 25px rgba(255, 191, 0, 0.3);
}
.btn-review:disabled { opacity: 0.4; cursor: not-allowed; transform: none; }

.btn-toggle {
  flex: 1;
  padding: 10px 14px;
  background: transparent;
  color: var(--text-muted);
  border: none;
  border-radius: 2px;
  font-weight: 700;
  font-size: 0.7rem;
  letter-spacing: 0.1em;
  cursor: pointer;
  text-transform: uppercase;
}

.btn-toggle:hover { color: white; }

.btn-toggle.active {
  background: rgba(255, 191, 0, 0.1);
  color: var(--gold);
  box-shadow: inset 0 0 10px rgba(255, 191, 0, 0.1);
}

/* ─── Section Titles ────────────────────────────────────────────────────── */
.section-title {
  font-size: 0.72rem;
  font-weight: 800;
  letter-spacing: 0.2em;
  color: var(--gold);
  text-transform: uppercase;
  margin-bottom: 12px;
  display: flex;
  align-items: center;
  gap: 8px;
}

.section-title::after {
  content: '';
  flex: 1;
  height: 1px;
  background: linear-gradient(to right, var(--gold), transparent);
  opacity: 0.2;
}

/* ─── Mastery Grid ──────────────────────────────────────────────────────── */
.mastery-grid-container {
  position: relative;
  padding-bottom: 100px;
}

.grid-toolbar {
  display: flex;
  gap: 10px;
  margin-bottom: 16px;
}

.sort-select {
  flex: 1;
  padding: 10px 14px;
  background: var(--surface);
  border: 1px solid var(--border);
  color: var(--text);
  border-radius: 2px;
  font-size: 0.85rem;
  width: auto;
  backdrop-filter: var(--glass);
}

.mastery-grid__cards {
  display: grid;
  grid-template-columns: repeat(auto-fill, minmax(100px, 1fr));
  gap: 10px;
}

/* ─── Vocab Cards ───────────────────────────────────────────────────────── */
.vocab-card {
  padding: 12px 10px;
  border-radius: 2px;
  border: 1px solid var(--border);
  background: var(--surface);
  backdrop-filter: var(--glass);
  user-select: none;
  cursor: pointer;
  position: relative;
  overflow: hidden;
  display: flex;
  flex-direction: column;
  gap: 4px;
}

.vocab-card:hover {
  border-color: var(--gold);
  background: rgba(255, 191, 0, 0.05);
}

/* DO NOT ALTER STATUS COLORS per requirement */
.vocab-card--not_started  { border-left: 3px solid #374151; }
.vocab-card--introduced   { border-left: 3px solid var(--blue); }
.vocab-card--practicing   { border-left: 3px solid var(--amber); }
.vocab-card--confident    { border-left: 3px solid #16a34a; }
.vocab-card--mastered     { border-left: 3px solid var(--cyan); }

.vocab-card__word {
  font-weight: 800;
  font-size: 0.95rem;
  color: var(--text);
  word-break: break-word;
}

.vocab-card__pos {
  font-size: 0.6rem;
  color: var(--text-muted);
  text-transform: uppercase;
  letter-spacing: 0.05em;
  font-weight: 700;
}

/* ─── Modals ────────────────────────────────────────────────────────── */
.modal-backdrop {
  position: fixed;
  inset: 0;
  background: rgba(0, 0, 0, 0.9);
  backdrop-filter: blur(12px);
  z-index: 5000;
  display: flex;
  align-items: center;
  justify-content: center;
  padding: 20px;
}

.modal-content {
  background: var(--surface-opaque);
  border: 1px solid var(--border);
  border-radius: 4px;
  width: 100%;
  max-width: 500px;
  max-height: 90vh;
  overflow-y: auto;
  position: relative;
  box-shadow: 0 20px 80px rgba(0,0,0,0.8), 0 0 40px rgba(255, 191, 0, 0.05);
}

/* ─── Side Panel Components ─────────────────────────────────────────── */
.side-panel-header {
  height: var(--header-height);
  padding: 0 16px;
  display: flex;
  align-items: center;
  border-bottom: 1px solid var(--border);
  background: rgba(5,5,5,0.95);
  backdrop-filter: var(--glass);
  position: sticky;
  top: 0;
  z-index: 10;
  flex-shrink: 0;
}

.side-panel-content {
  flex: 1;
  padding: 24px;
  overflow-y: auto;
}

.btn-back {
  background: var(--surface);
  border: 1px solid var(--border);
  color: white;
  padding: 8px 16px;
  border-radius: 2px;
  font-size: 0.7rem;
  font-weight: 900;
  display: flex;
  align-items: center;
  gap: 8px;
  letter-spacing: 0.1em;
}

.btn-back:hover {
  border-color: var(--gold);
  color: var(--gold);
}

/* ─── Drawer Styles ────────────────────────────────────────── */
.drawer-backdrop {
  position: fixed;
  inset: 0;
  background: rgba(0, 0, 0, 0.7);
  backdrop-filter: blur(6px);
  z-index: 1000;
}

/* Desktop: No backdrops for drawers/panels */
@media (min-width: 1024px) {
  .drawer-backdrop {
    display: none;
  }
}

.chat-drawer {
  height: 100%;
  background: var(--surface-opaque);
  border-left: 1px solid var(--border);
  display: flex;
  flex-direction: column;
}

/* ─── Scrollbars ────────────────────────────────────────────────────────── */
::-webkit-scrollbar { width: 4px; }
::-webkit-scrollbar-track { background: transparent; }
::-webkit-scrollbar-thumb { background: #222; border-radius: 2px; }
::-webkit-scrollbar-thumb:hover { background: var(--gold); }

/* ─── Misc ──────────────────────────────────────────────────────────────── */
button:active { transform: scale(0.96); }

.glass-panel {
  background: var(--surface);
  backdrop-filter: var(--glass);
  border: 1px solid var(--border);
  border-radius: 2px;
  padding: 20px;
}

.neon-text-gold { color: var(--gold); text-shadow: 0 0 10px rgba(255, 191, 0, 0.3); }
.neon-border-gold { border-color: var(--gold); box-shadow: 0 0 15px rgba(255, 191, 0, 0.1); }

